 1	import * as React from 'react';
 2	
 3	import { V1GPU, V1HostDevice, V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getGPUDevices, getHostDevices } from '@kubevirt-utils/resources/vm';
 6	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Card,
 9	  CardBody,
10	  CardTitle,
11	  Divider,
12	  Tab,
13	  Tabs,
14	  TabTitleText,
15	} from '@patternfly/react-core';
16	
17	import useHardwareDevicesColumns from './hooks/useHardwareDevicesColumns';
18	import VirtualMachinesOverviewTabHardwareDevicesRow from './VirtualMachinesOverviewTabHardwareDevicesRow';
19	
20	import './virtual-machines-overview-tab-hardware-devices.scss';
21	type VirtualMachinesOverviewTabHardwareDevicesProps = {
22	  vm: V1VirtualMachine;
23	};
24	
25	const VirtualMachinesOverviewTabHardwareDevices: React.FC<
26	  VirtualMachinesOverviewTabHardwareDevicesProps
27	> = ({ vm }) => {
28	  const { t } = useKubevirtTranslation();
29	  const columns = useHardwareDevicesColumns();
30	  const [activeTabKey, setActiveTabKey] = React.useState<number | string>(0);
31	  const hostDevices = getHostDevices(vm);
32	  const hostDevicesCount = hostDevices?.length;
33	  const gpus = getGPUDevices(vm);
34	  const gpusCount = gpus?.length;
35	
36	  const handleTabClick = (
37	    _: React.MouseEvent<HTMLElement, MouseEvent>,
38	    tabIndex: number | string,
39	  ) => {
40	    setActiveTabKey(tabIndex);
41	  };
42	
43	  return (
44	    <div className="VirtualMachinesOverviewTabHardware--main">
45	      <Card>
46	        <CardTitle className="text-muted">
47	          {t('Hardware devices ({{devices}})', { devices: hostDevicesCount + gpusCount })}
48	        </CardTitle>
49	        <Divider />
50	        <CardBody isFilled>
51	          <Tabs activeKey={activeTabKey} onSelect={handleTabClick}>
52	            <Tab
53	              eventKey={0}
54	              title={<TabTitleText>{t('GPU devices ({{gpusCount}})', { gpusCount })}</TabTitleText>}
55	            >
56	              <VirtualizedTable<V1GPU>
57	                columns={columns}
58	                data={gpus}
59	                loaded
60	                loadError={false}
61	                Row={VirtualMachinesOverviewTabHardwareDevicesRow}
62	                unfilteredData={gpus}
63	              />
64	            </Tab>
65	            <Tab
66	              title={
67	                <TabTitleText>
68	                  {t('Host devices ({{hostDevicesCount}})', { hostDevicesCount })}
69	                </TabTitleText>
70	              }
71	              eventKey={1}
72	            >
73	              <VirtualizedTable<V1HostDevice>
74	                columns={columns}
75	                data={hostDevices}
76	                loaded
77	                loadError={false}
78	                Row={VirtualMachinesOverviewTabHardwareDevicesRow}
79	                unfilteredData={hostDevices}
80	              />
81	            </Tab>
82	          </Tabs>
83	        </CardBody>
84	      </Card>
85	    </div>
86	  );
87	};
88	
89	export default VirtualMachinesOverviewTabHardwareDevices;

